import { useState, useRef, useEffect } from "react";
import { getWeather } from "../services/weatherAPI";

function Chatbot() {

    const [message, setMessage] = useState("");
    const [chat, setChat] = useState([]);
    const chatEndRef = useRef(null);

    const handleSend = async () => {

        if (!message.trim()) return;

        const userMsg = { sender: "user", text: message };
        setChat(prev => [...prev, userMsg]);

        const text = message.toLowerCase();

        let city = "chennai";
        if (text.includes("coimbatore")) city = "coimbatore";
        if (text.includes("madurai")) city = "madurai";
        if (text.includes("delhi")) city = "delhi";

        const weather = await getWeather(city);

        const botReply = {
            sender: "bot",
            text: `Temperature in ${city} is ${weather.temperature}°C and wind speed is ${weather.windspeed} km/h`
        };

        setChat(prev => [...prev, botReply]);
        setMessage("");
    };

    useEffect(() => {
        chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }, [chat]);

    return (

        <div style={{
            height: "90vh",
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
            justifyContent: "space-between"
        }}>

            <h1>AI Climate Chatbot</h1>

            {/* Chat area */}

            <div style={{
                width: "700px",
                flex: 1,
                overflowY: "auto",
                padding: "20px"
            }}>

                {chat.map((msg, index) => (

                    <div
                        key={index}
                        style={{
                            display: "flex",
                            justifyContent: msg.sender === "user" ? "flex-end" : "flex-start",
                            marginBottom: "15px"
                        }}
                    >

                        <div style={{
                            background: msg.sender === "user" ? "#4CAF50" : "#333",
                            color: "white",
                            padding: "12px 16px",
                            borderRadius: "10px",
                            maxWidth: "60%"
                        }}>
                            {msg.text}
                        </div>

                    </div>

                ))}

                <div ref={chatEndRef}></div>

            </div>

            {/* Input area */}

            <div style={{
                width: "700px",
                display: "flex",
                gap: "10px",
                marginBottom: "20px"
            }}>

                <input
                    style={{
                        flex: 1,
                        padding: "12px",
                        borderRadius: "8px",
                        border: "1px solid #444"
                    }}
                    placeholder="Ask climate question..."
                    value={message}
                    onChange={(e) => setMessage(e.target.value)}
                    onKeyDown={(e) => {
                        if (e.key === "Enter") handleSend();
                    }}
                />

                <button
                    style={{
                        padding: "10px 20px",
                        borderRadius: "8px"
                    }}
                    onClick={handleSend}
                >
                    Send
                </button>

            </div>

        </div>
    );
}

export default Chatbot;
